BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name ?owner ?ownerName WHERE {
  ?pkg vocab:NamedElement_name "TMT-APS%20DDD" .
  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:NamedElement_name ?name }
  OPTIONAL { ?pkg vocab:Element_owner ?owner }
  OPTIONAL { ?owner vocab:NamedElement_name ?ownerName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name ?nesting ?nestingName WHERE {
  ?pkg vocab:NamedElement_name "Alignment%20and%20Phasing%20System" .
  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:Package_nestingPackage ?nesting .
             ?nesting vocab:NamedElement_name ?nestingName }
}
LIMIT 25
